### 四、代码示例（含详细注释）

```jsx
// App.jsx
import React, { useState, useRef, useLayoutEffect, useEffect } from 'react';
import ReactDOM, { flushSync } from 'react-dom';

function BatchDemo() {
  const [count, setCount] = useState(0);
  const countRef = useRef(null);
  const logDivRef = useRef(null);

  // 演示 1：默认批处理行为（满足你“等函数执行完再更新”的需求）
  const handleBatchUpdate = () => {
    console.log('更新前 DOM:', logDivRef.current?.innerText); // 旧值
    setCount(prev => prev + 1);
    setCount(prev => prev + 2); // 第二次 setState 会被 React 合并
    setCount(prev => prev + 3);
    console.log('更新后（同步阶段） DOM:', logDivRef.current?.innerText); // 仍是旧值
    // React 会在当前调用栈结束后，统一计算 Virtual DOM Diff，然后一次性更新真实 DOM
  };

  // 演示 2：强制同步更新（满足你“一调用就更新”的需求，慎用！）
  const handleSyncUpdate = () => {
    console.log('同步更新前 DOM:', logDivRef.current?.innerText);
    flushSync(() => {
      setCount(prev => prev + 1);
      setCount(prev => prev + 2);
    });
    // flushSync 内部会立即执行渲染并提交 DOM，中断后续代码的执行上下文
    console.log('flushSync 后 DOM:', logDivRef.current?.innerText); // 已是新值
  };

  // 演示 3：正确读取更新后 DOM 的方式（推荐替代方案）
  useLayoutEffect(() => {
    // 每次 DOM 提交完成后立即执行，不会触发额外渲染
    if (logDivRef.current) {
      logDivRef.current.innerText = `count: ${count}`;
    }
  }, [count]);

  return (
    <div>
      <div ref={logDivRef}>初始值</div>
      <button onClick={handleBatchUpdate}>批量更新（默认）</button>
      <button onClick={handleSyncUpdate}>同步强刷（flushSync）</button>
    </div>
  );
}

export default BatchDemo;
```
💡 **关键注释说明**：
- `flushSync` 必须在 React 事件处理、合成事件或生命周期中调用，不能在纯 JS 回调（如 `setTimeout`、`fetch`）中使用，否则 React 会警告并回退到默认行为。
- `useLayoutEffect` 是 React 提供的“commit 阶段同步回调”，适合做尺寸测量、强制布局同步等操作。

