### 💻 二、企业级代码示例（React + Zustand + WebSocket + Three.js 联动模式）
该示例展示**如何安全地将物理世界状态同步至 UI，并驱动 3D 场景更新**。重点体现：增量同步、时钟补偿、生命周期清理、指令签名防护。

```tsx
// src/features/robot-dashboard/hooks/useRobotSync.ts
import { useEffect, useRef, useCallback } from 'react';
import { useRobotStore } from '@/store/robot';
import { createWebSocketManager } from '@/libs/ws-manager'; // 封装了心跳、重连、反压
import { useThree } from '@react-three/fiber'; // R3F 绑定

export function useRobotSync(robotId: string, jwtToken: string) {
  const wsRef = useRef<ReturnType<typeof createWebSocketManager> | null>(null);
  const setRobot = useRobotStore((s) => s.setState);
  const isMounted = useRef(true);
  const frameRef = useRef<number>(0);

  // ✅ 企业实践：使用 lastKnownTime 做前端插值补偿，避免物理抖动直接映射到 UI
  const SYNC_INTERVAL_MS = 30; // 100Hz 遥测降至 30ms 渲染步长，平衡性能与流畅度

  const handleTelemetry = useCallback((raw: Record<string, unknown>) => {
    const now = performance.now();
    setRobot((prev) => ({
      ...prev,
      telemetry: {
        position: raw.pos as number[] ?? prev.telemetry.position,
        orientation: raw.qtn as number[] ?? prev.telemetry.orientation,
        battery: raw.battery as number,
        // 记录服务器到达时间，用于前端动画插值与卡顿检测
        serverTimeNs: raw.time_ns as number,
        receivedAt: now,
      },
      isConnected: true,
    }));
  }, [setRobot]);

  useEffect(() => {
    isMounted.current = true;

    // 初始化安全通道
    wsRef.current = createWebSocketManager({
      url: `wss://api.example.com/v1/robots/${robotId}/stream`,
      headers: { Authorization: `Bearer ${jwtToken}` },
      onMessage: handleTelemetry,
      onReconnect: () => console.warn(`[Robot:${robotId}] 断线重连中，请检查 IoT Gateway`),
      maxRetries: 5,
      retryBaseMs: 200,
    });

    return () => {
      isMounted.current = false;
      wsRef.current?.close();
      cancelAnimationFrame(frameRef.current);
    };
  }, [robotId, jwtToken, handleTelemetry]);

  // 📦 指令下发接口（供按钮/键盘事件调用）
  const sendCommand = useCallback(
    (cmd: string, params?: Record<string, unknown>) => {
      if (!wsRef.current?.readyState) return;
      // 企业安全规范：所有控制指令必须带时间戳 + HMAC 签名
      const signedPayload = {
        cmd,
        params,
        ts: Date.now(),
        sign: generateHmacSign(`${robotId}:${cmd}:${params}`, jwtToken),
      };
      wsRef.current.send(signedPayload);
    },
    [robotId, jwtToken],
  );

  return { sendCommand };
}
```

#### 🎯 与你现有栈的契合点
- **React/Vue 通用原则**：状态只单向流动，物理世界是“权威源”，前端做视图层映射。Vue 可替换为 Pinia + Composition API，逻辑完全对等。
- **Vite 优势**：具身智能控制台常含大型 `.glb`/点云文件，Vite 的 `@rollup/plugin-image` + `unplugin-gltf` 可实现按需编译与 HMR 热更新，调试效率远高于 Webpack 默认配置。
- **UI 框架使用**：Ant Design / Element Plus 提供完善的表单、表格、告警通知，但**避免过度依赖 DOM 做实时图表**。高频数据（如 IMU 60Hz）应走 Canvas/WebGL 或 Web Worker 预计算。

